# break, continue, pass — controlling the search

files = ["readme.txt", "photo.jpg", "malware.exe", "notes.txt", "data.csv"]

# break — stop when threat found
print("=== THREAT SCAN ===")
for f in files:
    print(f"  Scanning {f}...", end=" ")
    if f.endswith(".exe"):
        print("THREAT FOUND! Stopping scan.")
        break
    print("Clean")

# continue — skip non-relevant files
print("\n=== TEXT FILE SEARCH ===")
for f in files:
    if not f.endswith(".txt"):
        continue  # Skip non-txt files
    print(f"  Found text file: {f}")

# pass — placeholder
print("\n=== FUTURE FEATURES ===")
for f in files:
    if f.endswith(".csv"):
        pass  # TODO: add CSV parser later
    else:
        pass  # TODO: add other file handlers

